//! System V message queue (msg*) implementation.
//!
//! Mirrors the structure of `shm.rs`: a global manager holding a
//! `BTreeMap<key/id -> Arc<MsgQueue>>` plus an id allocator, all guarded by
//! `SpinNoIrqLock`. NO-PANIC zone: every user-controlled id/size is validated
//! and the correct `SysError` is returned; we never index or unwrap on
//! user-controlled input.

use alloc::{
    collections::{btree_map::BTreeMap, btree_set::BTreeSet, vec_deque::VecDeque},
    sync::Arc,
    vec::Vec,
};

use crate::{sync::mutex::SpinNoIrqLock, timer::get_current_time_sec};

use super::IpcPerm64;

/// global message-queue manager instance
pub static MSG_MANAGER: MsgManager = MsgManager::new();

/// `struct msqid64_ds` (LP64 / asm-generic layout). Field order and sizes match
/// Linux exactly so that the LTP tests can `memcmp`/read specific offsets.
#[repr(C)]
#[derive(Debug, Clone, Copy)]
pub struct MsqidDs {
    /// Ownership and permissions
    pub msg_perm: IpcPerm64,
    /// Time of last msgsnd(2)
    pub msg_stime: i64,
    /// Time of last msgrcv(2)
    pub msg_rtime: i64,
    /// Time of creation / last modification via msgctl()
    pub msg_ctime: i64,
    /// Current number of bytes in queue
    pub msg_cbytes: u64,
    /// Current number of messages in queue
    pub msg_qnum: u64,
    /// Maximum number of bytes allowed in queue
    pub msg_qbytes: u64,
    /// PID of last msgsnd(2)
    pub msg_lspid: i32,
    /// PID of last msgrcv(2)
    pub msg_lrpid: i32,
    __unused4: u64,
    __unused5: u64,
}

/// Default maximum bytes a queue may hold, matching Linux's MSGMNB.
pub const MSGMNB: u64 = 16384;
/// Maximum size of a single message body (Linux MSGMAX).
pub const MSGMAX: usize = 8192;

impl MsqidDs {
    pub fn new(key: i32, cpid: usize, uid: u32, gid: u32, mode: u32) -> Self {
        Self {
            msg_perm: IpcPerm64::new(key, uid, gid, mode),
            msg_stime: 0,
            msg_rtime: 0,
            msg_ctime: get_current_time_sec() as i64,
            msg_cbytes: 0,
            msg_qnum: 0,
            msg_qbytes: MSGMNB,
            msg_lspid: cpid as i32,
            msg_lrpid: 0,
            __unused4: 0,
            __unused5: 0,
        }
    }
}

/// A single message stored in a queue.
pub struct Message {
    /// `long mtype`, must be > 0.
    pub mtype: isize,
    /// message body (`mtext`).
    pub data: Vec<u8>,
}

/// A System V message queue object.
pub struct MsgQueue {
    id: usize,
    pub msqid_ds: SpinNoIrqLock<MsqidDs>,
    pub messages: SpinNoIrqLock<VecDeque<Message>>,
}

impl MsgQueue {
    fn new(id: usize, key: i32, pid: usize, uid: u32, gid: u32, mode: u32) -> Self {
        Self {
            id,
            msqid_ds: SpinNoIrqLock::new(MsqidDs::new(key, pid, uid, gid, mode)),
            messages: SpinNoIrqLock::new(VecDeque::new()),
        }
    }

    /// get id
    pub fn get_id(&self) -> usize {
        self.id
    }
}

/// Message-queue manager.
pub struct MsgManager {
    queues: SpinNoIrqLock<BTreeMap<usize, Arc<MsgQueue>>>,
    id_alloc: SpinNoIrqLock<MsgIdAllocator>,
}

impl MsgManager {
    const fn new() -> Self {
        Self {
            queues: SpinNoIrqLock::new(BTreeMap::new()),
            id_alloc: SpinNoIrqLock::new(MsgIdAllocator::new()),
        }
    }

    /// look up a queue by id (id 0 is never valid)
    pub fn get(&self, id: usize) -> Option<Arc<MsgQueue>> {
        if id == 0 {
            return None;
        }
        self.queues.lock().get(&id).cloned()
    }

    /// allocate a fresh queue (IPC_PRIVATE style; key is recorded in perm)
    pub fn alloc(&self, key: i32, pid: usize, uid: u32, gid: u32, mode: u32) -> Option<Arc<MsgQueue>> {
        let id = self.id_alloc.lock().alloc()?;
        let q = Arc::new(MsgQueue::new(id, key, pid, uid, gid, mode));
        self.queues.lock().insert(id, q.clone());
        Some(q)
    }

    /// allocate a queue at a specific id (used to key by `key`). If a queue
    /// already exists at `id`, return it unchanged.
    pub fn alloc_at(
        &self,
        id: usize,
        key: i32,
        pid: usize,
        uid: u32,
        gid: u32,
        mode: u32,
    ) -> Option<Arc<MsgQueue>> {
        if id == 0 {
            return self.alloc(key, pid, uid, gid, mode);
        }
        if let Some(q) = self.queues.lock().get(&id).cloned() {
            return Some(q);
        }
        self.id_alloc.lock().alloc_at(id)?;
        let q = Arc::new(MsgQueue::new(id, key, pid, uid, gid, mode));
        self.queues.lock().insert(id, q.clone());
        Some(q)
    }

    /// remove a queue by id, returning it if present.
    pub fn remove(&self, id: usize) -> Option<Arc<MsgQueue>> {
        let _ = self.id_alloc.lock().dealloc(id);
        self.queues.lock().remove(&id)
    }

    /// snapshot of currently-allocated ids (for MSG_STAT/MSG_INFO indexing).
    pub fn ids(&self) -> Vec<usize> {
        self.queues.lock().keys().copied().collect()
    }
}

/// Message-queue id allocator (copied from `ShmIdAllocator`).
pub struct MsgIdAllocator {
    cur: usize,
    pool: BTreeSet<usize>,
}

impl MsgIdAllocator {
    pub const fn new() -> Self {
        Self {
            cur: 0,
            pool: BTreeSet::new(),
        }
    }

    pub fn alloc(&mut self) -> Option<usize> {
        let mut times = 1000;
        loop {
            if self.cur == usize::MAX {
                self.cur = 0;
            }
            self.cur += 1;
            if self.pool.insert(self.cur) {
                break Some(self.cur);
            }
            times -= 1;
            if times == 0 {
                break None;
            }
        }
    }

    pub fn alloc_at(&mut self, id: usize) -> Option<usize> {
        if id == 0 {
            self.alloc()
        } else if self.pool.contains(&id) {
            None
        } else {
            self.cur = self.cur.max(id);
            self.pool.insert(id);
            Some(id)
        }
    }

    pub fn dealloc(&mut self, id: usize) -> Result<(), ()> {
        if self.pool.remove(&id) {
            Ok(())
        } else {
            Err(())
        }
    }
}

