ENTRY(_start)
BASE_ADDRESS = 0xFFFFFFC080200000;
/* sv39 kernel-half offset (vaddr - paddr). The kernel is LINKED at the high VMA
   (its code and pointers assume it) but must be LOADED at physical RAM 0x80200000
   so `qemu -kernel <ELF> -bios default` can place it: qemu places PT_LOAD by
   p_paddr, and a high p_paddr yields "No enough memory to place DTB". We keep VMA
   high and set LMA = VMA - PHYS_OFFSET = physical via AT() on each section, letting
   rust-lld keep the natural per-flag segment split (so .bss stays NOBITS and the
   file stays small). e_entry is forced to the physical _start (0x80200000) by
   `objcopy --set-start` in mk/kernel.mk, since OpenSBI enters e_entry with paging
   off. Net: a spec-required ELF that loads/boots identically to the raw binary. */
PHYS_OFFSET = 0xFFFFFFC000000000;

SECTIONS
{
    . = BASE_ADDRESS;
    skernel = .;

    stext = .;
    .text : AT(ADDR(.text) - PHYS_OFFSET) {
        *(.text.entry)
        *(.text .text.*)
    }

    . = ALIGN(4K);
    etext = .;
    srodata = .;
    .rodata : AT(ADDR(.rodata) - PHYS_OFFSET) {
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
    }

    . = ALIGN(4K);
    erodata = .;
    sdata = .;
    .data : AT(ADDR(.data) - PHYS_OFFSET) {
        *(.data .data.*)
        *(.sdata .sdata.*)
    }

    . = ALIGN(4K);
    edata = .;
    sbss_with_stack = .;
    kernel_stack_bottom = .;
    .bss : AT(ADDR(.bss) - PHYS_OFFSET) {
        *(.bss.stack)
        kernel_stack_top = .;
        sbss = .;
        *(.bss .bss.*)
        *(.sbss .sbss.*)
    }

    . = ALIGN(4K);
    ebss = .;
    ekernel = .;

    /DISCARD/ : {
        *(.eh_frame)
    }
}
